void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = mix( vUvOriginal,vUv,0.2);

vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*1.5 + rand_frame.xy;
vUv  -= (vec2(0,1)*(lum(GetPixel(vUv)-0.35))*uTexSize.zw*32)*(lum(GetPixel(vUv))-0.4);
